// Lead scoring algorithm
// Max score: 100 points
const lead = $input.first().json;

let score = 0;
const factors = [];

// Budget (30pts)
const budget = Number(lead.budget_max) || 0;
if (budget >= 1000000) { score += 30; factors.push('Budget 1M+ (30pts)'); }
else if (budget >= 500000) { score += 22; factors.push('Budget 500K+ (22pts)'); }
else if (budget >= 200000) { score += 15; factors.push('Budget 200K+ (15pts)'); }
else if (budget >= 100000) { score += 8; factors.push('Budget 100K+ (8pts)'); }

// Engagement activity (30pts)
const visits = Number(lead.visit_count) || 0;
const inquiries = Number(lead.inquiry_count) || 0;
const replies = Number(lead.reply_count) || 0;
const engagementScore = Math.min(30, (visits * 10) + (inquiries * 5) + (replies * 3));
score += engagementScore;
if (engagementScore > 0) factors.push(`Engagement: ${visits}v/${inquiries}i/${replies}r (${engagementScore}pts)`);

// Recency (20pts)
const daysSinceActivity = lead.latest_activity
  ? Math.floor((Date.now() - new Date(lead.latest_activity).getTime()) / 86400000)
  : 999;
if (daysSinceActivity <= 1) { score += 20; factors.push('Activo hoje (20pts)'); }
else if (daysSinceActivity <= 7) { score += 15; factors.push('Activo esta semana (15pts)'); }
else if (daysSinceActivity <= 30) { score += 8; factors.push('Activo este mês (8pts)'); }
else if (daysSinceActivity <= 60) { score += 3; factors.push('Activo 60d (3pts)'); }

// Source quality (20pts)
const sourceScores = {
  referral: 20, 'word-of-mouth': 20,
  linkedin: 15, 'direct-contact': 15,
  website: 10, portal: 8,
  'social-media': 6, other: 3
};
const sourceScore = sourceScores[lead.source] || 3;
score += sourceScore;
factors.push(`Source: ${lead.source} (${sourceScore}pts)`);

// Tier assignment
let tier = 'D';
if (score >= 80) tier = 'A';
else if (score >= 60) tier = 'B';
else if (score >= 40) tier = 'C';

return [{
  json: {
    contact_id: lead.id,
    new_score: score,
    previous_score: lead.current_score,
    score_delta: score - (lead.current_score || 0),
    tier,
    scoring_factors: factors,
    scored_at: new Date().toISOString()
  }
}];
